import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link, NavLink, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import './App.css';

function Navigation() {
  const { isAuthenticated, user, logout } = useAuth();

  return (
    <header className="App-header">
      <div className="header-content">
        <Link to="/" className="brand" aria-label="Go to Home">
          <div className="brand-mark">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"></path>
              <polyline points="3.27 6.96 12 12.01 20.73 6.96"></polyline>
              <line x1="12" y1="22.08" x2="12" y2="12"></line>
            </svg>
          </div>
          <div className="brand-text">
            <div className="brand-title">TalentScout AI</div>
            <div className="brand-subtitle">Intelligent Hiring Platform</div>
          </div>
        </Link>
        <nav>
          <NavLink to="/" className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Home</NavLink>
          {!isAuthenticated ? (
            <>
              <NavLink to="/login" className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Login</NavLink>
              <NavLink to="/register" className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Register</NavLink>
            </>
          ) : (
            <>
              <span className="user-info">
                Welcome, {user?.name} ({user?.role})
              </span>
              <button onClick={logout} className="logout-btn">Logout</button>
            </>
          )}
        </nav>
      </div>
    </header>
  );
}

function App() {
  return (
    <AuthProvider>
      <Router>
        <div className="App">
          <Navigation />
          
          <main className="App-main">
            <Routes>
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              
              <Route 
                path="/" 
                element={
                  <ProtectedRoute>
                    <Home />
                  </ProtectedRoute>
                } 
              />
              
              <Route 
                path="/admin/dashboard" 
                element={
                  <ProtectedRoute allowedRoles={['admin']}>
                    <Home />
                  </ProtectedRoute>
                } 
              />
              
              <Route 
                path="/user/dashboard" 
                element={
                  <ProtectedRoute allowedRoles={['user']}>
                    <Home />
                  </ProtectedRoute>
                } 
              />

              <Route path="/unauthorized" element={
                <div style={{ textAlign: 'center', padding: '50px' }}>
                  <h2>Unauthorized Access</h2>
                  <p>You don't have permission to access this page.</p>
                  <Link to="/">Go Home</Link>
                </div>
              } />

              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
          
          <footer className="App-footer">
            <p>&copy; 2026 AI-Powered Resume Shortlisting System</p>
          </footer>
        </div>
      </Router>
    </AuthProvider>
  );
}

export default App;
